sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

    // Clear any previous UI messages to keep the form clean
    g_form.clearMessages();

    var ga = new GlideAjax('TelecomIncidentUtils');

    ga.addParam('sysparm_name', 'getNetworkElementDetails');

    ga.addParam('sysparm_ci_id', newValue);

    ga.getXMLAnswer(function(answer) {
        // Guard Clause: Ensure we received a valid response
        if (!answer) {
            console.error('Telecom UI: No response received from server.');
            return;
        }

        try {
            var parsedData = JSON.parse(answer);

            //  Construct the informational message
            var infoMsg = 'Network Element Info | Location: ' + parsedData.location + 
                          ' | Category: ' + parsedData.category;

            //  Display the message to the support agent
            g_form.addInfoMessage(infoMsg);

        } catch (e) {
            // Fail gracefully if JSON parsing breaks
            console.error('Telecom UI: Failed to parse CI details JSON. Error: ' + e.message);
        }
    });

}
